CREATE TABLE IF NOT EXISTS "roles" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "description" text, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "permissions" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "description" text, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "role_user" ("id" integer primary key autoincrement not null, "role_id" integer not null, "user_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("role_id") references "roles"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "permission_role" ("id" integer primary key autoincrement not null, "permission_id" integer not null, "role_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("permission_id") references "permissions"("id") on delete cascade, foreign key("role_id") references "roles"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "smtp_accounts" ("id" integer primary key autoincrement not null, "user_id" integer not null, "name" varchar not null, "host" varchar not null, "port" integer not null default '587', "username" text not null, "password" text not null, "encryption" varchar not null default 'tls', "from_address" varchar not null, "from_name" varchar, "is_default" tinyint(1) not null default '0', "is_active" tinyint(1) not null default '1', "daily_limit" integer not null default '500', "monthly_limit" integer not null default '10000', "is_verified" tinyint(1) not null default '0', "last_tested_at" datetime, "last_test_error" text, "status" varchar check ("status" in ('pending', 'verified', 'failed', 'suspended')) not null default 'pending', "emails_sent_today" integer not null default '0', "emails_sent_month" integer not null default '0', "last_used_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
