CREATE TABLE IF NOT EXISTS "campaigns" ("id" integer primary key autoincrement not null, "user_id" integer not null, "smtp_account_id" integer, "name" varchar not null, "subject" varchar not null, "content" text, "html_content" text, "plain_text_content" text, "status" varchar check ("status" in ('draft', 'scheduled', 'sending', 'sent', 'cancelled')) not null default 'draft', "scheduled_at" datetime, "sent_at" datetime, "total_recipients" integer not null default '0', "sent_count" integer not null default '0', "opened_count" integer not null default '0', "clicked_count" integer not null default '0', "bounced_count" integer not null default '0', "unsubscribed_count" integer not null default '0', "settings" text, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("smtp_account_id") references "smtp_accounts"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "subscriber_lists" ("id" integer primary key autoincrement not null, "user_id" integer not null, "name" varchar not null, "description" text, "subscriber_count" integer not null default '0', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "subscribers" ("id" integer primary key autoincrement not null, "user_id" integer not null, "subscriber_list_id" integer, "email" varchar not null, "first_name" varchar, "last_name" varchar, "phone" varchar, "metadata" text, "status" varchar check ("status" in ('active', 'unsubscribed', 'bounced', 'complained')) not null default 'active', "subscribed_at" datetime not null default CURRENT_TIMESTAMP, "unsubscribed_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("subscriber_list_id") references "subscriber_lists"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "analytics" ("id" integer primary key autoincrement not null, "campaign_id" integer not null, "subscriber_id" integer, "event_type" varchar not null, "url" varchar, "ip_address" varchar, "user_agent" varchar, "occurred_at" datetime not null, "created_at" datetime, "updated_at" datetime, foreign key("campaign_id") references "campaigns"("id") on delete cascade, foreign key("subscriber_id") references "subscribers"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "campaign_subscribers" ("id" integer primary key autoincrement not null, "campaign_id" integer not null, "subscriber_id" integer not null, "status" varchar not null default 'pending', "sent_at" datetime, "opened_at" datetime, "clicked_at" datetime, "bounced_at" datetime, "tracking_token" varchar, "message_id" varchar, "created_at" datetime, "updated_at" datetime, foreign key("campaign_id") references "campaigns"("id") on delete cascade, foreign key("subscriber_id") references "subscribers"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "campaign_send_logs" ("id" integer primary key autoincrement not null, "campaign_id" integer not null, "subscriber_id" integer not null, "smtp_account_id" integer not null, "message_id" varchar, "from_address" varchar, "to_address" varchar, "subject" varchar, "status" varchar not null default 'pending', "error_message" text, "sent_at" datetime, "delivered_at" datetime, "opened_at" datetime, "clicked_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("campaign_id") references "campaigns"("id") on delete cascade, foreign key("subscriber_id") references "subscribers"("id") on delete cascade, foreign key("smtp_account_id") references "smtp_accounts"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "email_templates" ("id" integer primary key autoincrement not null, "user_id" integer not null, "name" varchar not null, "subject" varchar not null, "content" text not null, "html_content" text not null, "plain_text_content" text, "thumbnail" varchar, "is_public" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "campaign_duplicates" ("id" integer primary key autoincrement not null, "original_campaign_id" integer not null, "new_campaign_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("original_campaign_id") references "campaigns"("id") on delete cascade, foreign key("new_campaign_id") references "campaigns"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "campaign_link_clicks" ("id" integer primary key autoincrement not null, "campaign_link_id" integer not null, "subscriber_id" integer, "ip_address" varchar, "user_agent" varchar, "clicked_at" datetime not null, "created_at" datetime, "updated_at" datetime, foreign key("campaign_link_id") references "campaign_links"("id") on delete cascade, foreign key("subscriber_id") references "subscribers"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "campaign_links" ("id" integer primary key autoincrement not null, "campaign_id" integer not null, "url" varchar not null, "hash" varchar not null, "click_count" integer not null default '0', "unique_click_count" integer not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("campaign_id") references "campaigns"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "vendor_profiles" ("id" integer primary key autoincrement not null, "user_id" integer not null, "shop_name" varchar, "description" text, "logo" varchar, "website" varchar, "is_verified" tinyint(1) not null default '0', "status" varchar check ("status" in ('pending', 'active', 'suspended')) not null default 'pending', "commission_rate" numeric not null default '10', "total_earnings" numeric not null default '0', "pending_earnings" numeric not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "marketplace_listings" ("id" integer primary key autoincrement not null, "vendor_id" integer not null, "name" varchar not null, "description" text not null, "host" varchar not null, "port" integer not null default '587', "encryption" varchar not null default 'tls', "from_address" varchar not null, "from_name" varchar, "pricing_type" varchar check ("pricing_type" in ('per_email', 'subscription')) not null default 'per_email', "price_per_email" numeric, "monthly_subscription" numeric, "free_emails" integer not null default '0', "included_emails" integer, "daily_limit" integer not null default '1000', "monthly_limit" integer not null default '30000', "features" text, "thumbnail" varchar, "status" varchar check ("status" in ('draft', 'pending', 'active', 'rejected', 'suspended')) not null default 'draft', "rejection_reason" text, "view_count" integer not null default '0', "purchase_count" integer not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("vendor_id") references "vendor_profiles"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "marketplace_purchases" ("id" integer primary key autoincrement not null, "user_id" integer not null, "listing_id" integer not null, "vendor_id" integer not null, "type" varchar check ("type" in ('one_time', 'subscription')) not null default 'one_time', "amount" numeric not null, "vendor_amount" numeric not null, "commission_amount" numeric not null, "commission_rate" numeric not null, "emails_credit" integer not null default '0', "emails_used" integer not null default '0', "is_subscription" tinyint(1) not null default '0', "subscription_start" date, "subscription_end" date, "subscription_active" tinyint(1) not null default '0', "stripe_subscription_id" varchar, "stripe_payment_id" varchar, "payment_status" varchar check ("payment_status" in ('pending', 'completed', 'failed', 'refunded')) not null default 'pending', "is_active" tinyint(1) not null default '1', "purchased_at" datetime not null default CURRENT_TIMESTAMP, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("listing_id") references "marketplace_listings"("id") on delete cascade, foreign key("vendor_id") references "vendor_profiles"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "marketplace_smtp_accounts" ("id" integer primary key autoincrement not null, "user_id" integer not null, "purchase_id" integer not null, "listing_id" integer not null, "name" varchar not null, "host" varchar not null, "port" integer not null, "encryption" varchar not null, "from_address" varchar not null, "from_name" varchar, "username" text not null, "password" text not null, "daily_limit" integer not null, "monthly_limit" integer not null, "emails_sent_today" integer not null default '0', "emails_sent_month" integer not null default '0', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("purchase_id") references "marketplace_purchases"("id") on delete cascade, foreign key("listing_id") references "marketplace_listings"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "marketplace_transactions" ("id" integer primary key autoincrement not null, "vendor_id" integer not null, "purchase_id" integer, "type" varchar check ("type" in ('sale', 'commission', 'payout', 'refund')) not null default 'sale', "amount" numeric not null, "commission_amount" numeric not null default '0', "net_amount" numeric not null, "stripe_transaction_id" varchar, "status" varchar check ("status" in ('pending', 'completed', 'failed')) not null default 'pending', "description" text, "created_at" datetime, "updated_at" datetime, foreign key("vendor_id") references "vendor_profiles"("id") on delete cascade, foreign key("purchase_id") references "marketplace_purchases"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "vendor_payouts" ("id" integer primary key autoincrement not null, "vendor_id" integer not null, "amount" numeric not null, "fee" numeric not null default '0', "net_amount" numeric not null, "stripe_transfer_id" varchar, "status" varchar check ("status" in ('pending', 'processing', 'completed', 'failed')) not null default 'pending', "notes" text, "processed_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("vendor_id") references "vendor_profiles"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "marketplace_favorites" ("id" integer primary key autoincrement not null, "user_id" integer not null, "listing_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("listing_id") references "marketplace_listings"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "campaign_ab_tests" ("id" integer primary key autoincrement not null, "campaign_id" integer not null, "variant_a_subject" varchar, "variant_b_subject" varchar, "variant_a_html_content" text, "variant_b_html_content" text, "variant_a_open_count" integer not null default '0', "variant_b_open_count" integer not null default '0', "variant_a_click_count" integer not null default '0', "variant_b_click_count" integer not null default '0', "winner" varchar, "test_started_at" datetime, "test_ended_at" datetime, "test_duration_hours" integer not null default '24', "sample_size_per_variant" integer not null default '100', "created_at" datetime, "updated_at" datetime, foreign key("campaign_id") references "campaigns"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "email_warmups" ("id" integer primary key autoincrement not null, "smtp_account_id" integer not null, "status" varchar not null default 'inactive', "current_daily_limit" integer not null default '10', "target_daily_limit" integer not null default '500', "current_day" integer not null default '0', "total_days" integer not null default '30', "started_at" datetime, "paused_at" datetime, "completed_at" datetime, "settings" text, "created_at" datetime, "updated_at" datetime, foreign key("smtp_account_id") references "smtp_accounts"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "warmup_emails" ("id" integer primary key autoincrement not null, "email_warmup_id" integer not null, "smtp_account_id" integer not null, "recipient_email" varchar not null, "subject" varchar, "type" varchar not null, "status" varchar not null default 'pending', "sent_at" datetime, "delivered_at" datetime, "opened_at" datetime, "replied_at" datetime, "send_order" integer, "created_at" datetime, "updated_at" datetime, foreign key("email_warmup_id") references "email_warmups"("id") on delete cascade, foreign key("smtp_account_id") references "smtp_accounts"("id") on delete cascade);
