CREATE TABLE IF NOT EXISTS "warmup_auto_replies" ("id" integer primary key autoincrement not null, "email_pattern" varchar not null, "reply_subject" varchar not null, "reply_body" text not null, "response_delay_hours" integer not null default '24', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "warmup_daily_stats" ("id" integer primary key autoincrement not null, "email_warmup_id" integer not null, "date" date not null, "emails_sent" integer not null default '0', "emails_delivered" integer not null default '0', "emails_opened" integer not null default '0', "emails_replied" integer not null default '0', "emails_clicked" integer not null default '0', "daily_limit" integer not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("email_warmup_id") references "email_warmups"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "plans" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "description" text, "price" numeric not null default '0', "billing_period" integer not null default '30', "max_emails" integer not null default '0', "max_subscribers" integer not null default '0', "max_smtp_accounts" integer not null default '0', "max_campaigns" integer not null default '0', "has_analytics" tinyint(1) not null default '0', "has_ai" tinyint(1) not null default '0', "has_api" tinyint(1) not null default '0', "has_white_label" tinyint(1) not null default '0', "has_priority_support" tinyint(1) not null default '0', "sort_order" integer not null default '0', "is_active" tinyint(1) not null default '1', "is_featured" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "subscriptions" ("id" integer primary key autoincrement not null, "user_id" integer not null, "plan_id" integer not null, "status" varchar not null default 'active', "stripe_subscription_id" varchar, "stripe_customer_id" varchar, "trial_ends_at" datetime, "starts_at" datetime, "ends_at" datetime, "cancels_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("plan_id") references "plans"("id") on delete restrict);
