CREATE TABLE IF NOT EXISTS "payment_methods" ("id" integer primary key autoincrement not null, "user_id" integer not null, "type" varchar not null, "stripe_payment_method_id" varchar, "last4" varchar, "brand" varchar, "exp_month" integer, "exp_year" integer, "is_default" tinyint(1) not null default '0', "is_valid" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "invoices" ("id" integer primary key autoincrement not null, "user_id" integer not null, "subscription_id" integer, "stripe_invoice_id" varchar, "number" varchar, "subtotal" numeric not null default '0', "tax" numeric not null default '0', "total" numeric not null default '0', "currency" varchar not null default 'USD', "status" varchar not null default 'draft', "due_date" datetime, "paid_at" datetime, "invoice_date" datetime, "notes" text, "line_items" text, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("subscription_id") references "subscriptions"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "transactions" ("id" integer primary key autoincrement not null, "user_id" integer not null, "invoice_id" integer, "stripe_payment_id" varchar, "type" varchar not null, "amount" numeric not null default '0', "fee" numeric not null default '0', "currency" varchar not null default 'USD', "status" varchar not null default 'pending', "payment_method" varchar, "description" text, "metadata" text, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("invoice_id") references "invoices"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "credits" ("id" integer primary key autoincrement not null, "user_id" integer not null, "amount" integer not null, "type" varchar not null, "description" varchar, "transaction_id" integer, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("transaction_id") references "transactions"("id") on delete set null);
